function setdAhI()
    local items = gg.getListItems()

    for i, v in ipairs(items) do
        if v.name == "EditValue_1" then
            v.value = add_to_1
        elseif v.name == "EditValue_2" then
            v.value = add_to_2
        elseif v.name == "EditValue_3" then
            v.value = add_to_3
        elseif v.name == "EditValue_4" then
            v.value = add_to_4
        elseif v.name == "EditValue_5" then
            v.value = add_to_5
        elseif v.name == "EditValue_6" then
            v.value = add_to_6
        elseif v.name == "Zero_Value" then
            v.value = add_to_7
        elseif v.name == "EditAmount" then
            v.value = add_to_8
        end
    end
    gg.setValues(items)
    gg.sleep(100)
end
function setg(offset, new)
  local table = gg.getResults(40)
  for i = 1, #table do
     table[i]["address"] = table[i]["address"] + offset 
     table[i]["flags"] = gg.TYPE_DWORD 
     table[i]["value"] = new
     table[i]["freezeType"] = gg.FREEZE_NORMAL
     table[i]["freeze"] = true
     gg.addListItems(table)
  end
end
function setd(offset, new)
  local table = gg.getResults(30)
  for i = 1, #table do
     table[i]["address"] = table[i]["address"] + offset 
     table[i]["flags"] = gg.TYPE_DWORD
     table[i]["value"] = new
     table[i]["freeze"] = true
     gg.addListItems(table) 
  end
end
function setd2(offset, new)
  local table = gg.getResults(30)
  for i = 1, #table do
     table[i]["address"] = table[i]["address"] + offset 
     table[i]["flags"] = gg.TYPE_DWORD
