function SearchSkin()
  local input = gg.prompt(
    {"🔍 CARI SKIN (KETIK KEYWORD)"},
    {""},
    {"text"}
  )
  if input == nil then return end

  local key = string.lower(input[1])
  local names = {}
  local refs = {}

  for i, v in ipairs(SkinData) do
    if string.find(string.lower(v.name), key, 1, true) then
      table.insert(names, "🎎 • " .. v.name)
      refs[#names] = v.code
    end
  end

  if #names == 0 then
    gg.alert(" 😢  SKIN TIDAK DITEMUKAN")
    return
  end

  local pick = gg.choice(names, nil, "SKIN DITEMUKAN😍")
  if pick == nil then return end

  local selected = refs[pick]

