function XP_Wheat(isFree)
    gg.toast("Loading...🥰")
    gg.processResume()
    gg.clearResults()
    gg.setVisible(false)

    gg.searchNumber("120;300", gg.TYPE_FLOAT)
    gg.refineNumber("120", gg.TYPE_FLOAT)

    local xps = gg.prompt(
        {"Masukkan Jumlah XP (1 - 100000000)"},
        {"1"},
        {"number"}
    )

    if not xps then
        Menu_Option(100002)
        return
    end
    local xpValue = tonumber(xps[1])

    if not xpValue then
        gg.alert("Masukkan angka yang valid!")
        return
    end
    if xpValue < 1 or xpValue > 100000000 then
        gg.alert("XP harus antara 1 sampai 100000000!")
        return
    end

    setd(0, 0)
    setd(16, 0)
    setd(20, xpValue)

    gg.clearResults()
    gg.clearList()

    gg.toast("XP berhasil diubah menjadi " .. xpValue)
end


