function seth(offset, new)
  local table = gg.getResults(30)
  for i = 1, #table do
     table[i]["address"] = table[i]["address"] + offset 
     table[i]["flags"] = gg.TYPE_DWORD
     table[i]["value"] = new.."X4"
     gg.addListItems(table) 
     gg.setValues(table)
  end
end

