function Tcash_Coin_Exp(variac)
    LoadingAuto("Loading...", 2)
    gg.processResume()
    gg.clearResults()
    gg.setVisible(false)

    local amount = nil


    if variac == "tcash" then
        local p = gg.prompt(
            {"Amount of tcash? [0;100000] Max 100000/3Month"},
            {1},
            {"number"}
        )
        if not p then return end
        amount = tonumber(p[1])
        if not amount or amount < 0 or amount > 100000 then
            gg.alert("❌ Invalid Amount")
            return
        end

    elseif variac == "coins" then
        local p = gg.prompt(
            {"Amount of coins?"},
            {1},
            {"number"}
        )
        if not p then return end
        amount = tonumber(p[1])
        if not amount or amount < 10000 or amount > 750000 then
            gg.alert("❌ Invalid Amount")
            return
        end

    elseif variac == "experience" then
        local p = gg.prompt(
            {"Amount of exp?"},
            {1},
            {"number"}
        )
        if not p then return end
        amount = tonumber(p[1])
        if not amount or amount < 10000 or amount > 10000000 then
            gg.alert("❌ Invalid Amount")
            return
        end
    end

    if variac == "tcash" then

        add_to_1 = 1935762184
        add_to_2 = 104
        add_to_3 = 0
        add_to_4 = 0
        add_to_5 = 0
        add_to_6 = 0
        add_to_7 = 0
        add_to_8 = amount

        setdAhI()

    elseif variac == "coins" then

        add_to_1 = "696F630Ah"
        add_to_2 = "0000736Eh"
        add_to_3 = "00000000h"
        add_to_4 = "00000000h"
        add_to_5 = "00000000h"
        add_to_6 = "00000000h"
        add_to_7 = "00000000h"
        add_to_8 = amount

        setdAhI()

    elseif variac == "experience" then

        add_to_1 = "70786506h"
        add_to_2 = "00303000h"
        add_to_3 = "00000000h"
        add_to_4 = "00000000h"
        add_to_5 = "00000000h"
        add_to_6 = "00000000h"
        add_to_7 = "00000000h"
        add_to_8 = amount

        setdAhI()
    end

    gg.clearResults()
end


