function Open_Community_Building()
	
    -- NURSERY
    gg.clearResults()
	gg.setRanges(gg.REGION_C_ALLOC | gg.REGION_ANONYMOUS | gg.REGION_OTHER)
    gg.searchNumber(
        "6963731Ah;65636E65h;6573756Dh;65006D75h;79000072h:17",
        gg.TYPE_DWORD
    )

    gg.refineNumber("6963731Ah", gg.TYPE_DWORD)

    local results = gg.getResults(2)

    if #results < 2 then
        gg.alert("❌ NURSERY NOT FOUND")
        return
    end

    local base = nil

    for _, r in ipairs(results) do
        local v = gg.getValues({
            {address = r.address + 6 * 4, flags = gg.TYPE_DWORD},
            {address = r.address + 7 * 4, flags = gg.TYPE_DWORD}
        })

        if (v[1].value ~ v[2].value) == 128 then
            base = r.address
            break
        end
    end

    if not base then
        gg.alert("❌ NURSERY XOR 128 NOT FOUND")
        return
    end

    local t = {}

    for row = 6, 132, 40 do
        t[#t+1] = {address = base + row * 4, flags = gg.TYPE_DWORD, value = 0}
        t[#t+1] = {address = base + (row + 1) * 4, flags = gg.TYPE_DWORD, value = 0}
        t[#t+1] = {address = base + (row + 3) * 4, flags = gg.TYPE_DWORD, value = 0}
        t[#t+1] = {address = base + (row + 4) * 4, flags = gg.TYPE_DWORD, value = 0}
    end

    gg.setValues(t)
    gg.addListItems(t)

    -- SCHOOL
    gg.clearResults()

    gg.searchNumber(
        "6F747312h;315F6572h;31003130h;6E617200h;79000074h;68637312h;5F6C6F6Fh;31003176h;6E617200h;79000074h:177",
        gg.TYPE_DWORD
    )

    gg.refineNumber("6F747312h", gg.TYPE_DWORD)

    local results2 = gg.getResults(10)

    if #results2 < 2 then
        gg.alert("❌ SCHOOL NOT FOUND")
        return
    end

    local base2 = nil

    for _, r in ipairs(results2) do
        local v = gg.getValues({
            {address = r.address + 6 * 4, flags = gg.TYPE_DWORD},
            {address = r.address + 7 * 4, flags = gg.TYPE_DWORD}
        })

        if (v[1].value ~ v[2].value) == 5 then
            base2 = r.address
            break
        end
    end

    if not base2 then
        gg.alert("❌ SCHOOL XOR 5 NOT FOUND")
        return
    end

    local t2 = {}

    for row = 6, 4354, 40 do
        t2[#t2+1] = {address = base2 + row * 4, flags = gg.TYPE_DWORD, value = 0}
        t2[#t2+1] = {address = base2 + (row + 1) * 4, flags = gg.TYPE_DWORD, value = 0}
        t2[#t2+1] = {address = base2 + (row + 3) * 4, flags = gg.TYPE_DWORD, value = 0}
        t2[#t2+1] = {address = base2 + (row + 4) * 4, flags = gg.TYPE_DWORD, value = 0}
    end

    gg.setValues(t2)
    gg.addListItems(t2)

    gg.clearResults()
    gg.toast("✅ ALL COMMUNITY BUILDINGS UNLOCKED")

end

