function Helicopter(data, dyn)
    LoadingAuto("Search Skin Helicopter", 2)
    gg.processResume()
    gg.clearResults()

    gg.searchNumber("7596256584804597814", gg.TYPE_QWORD)

    local val = gg.getResults(gg.getResultsCount())

    for _, v in ipairs(val) do
        v.address = v.address + 0x2C
    end

    val = gg.getValues(val)

    for _, v in ipairs(val) do
        v.address = v.value
    end

    for i, value in ipairs(data) do
        gg.setValues({{
            address = val[1].address + (i - 1) * 0x4,
            flags = gg.TYPE_DWORD,
            value = value
        }})
    end

    dyn()
end

