  gg.processResume()
  gg.clearResults()
  gg.setVisible(false)
 
local int50 = nil

if varcJExpe_2 == "rExpe_2" then

    local t = gg.prompt(
        {
            "Hari",
            "Jam",
            "Menit"
        },
        {
            "0",
            "1",
            "0"
        },
        {
            "number",
            "number",
            "number"
        }
    )

    -- Cancel
    if not t then
        gg.toast("CANCELLED")
        return
    end

    local hari  = tonumber(t[1]) or 0
    local jam   = tonumber(t[2]) or 0
    local menit = tonumber(t[3]) or 0

    -- ❌ validasi hari maksimal 365
    if hari < 0 or hari > 365 then
        gg.alert("❌ MAKSIMAL 365 HARI")
        return
    end

    -- Hitung total detik
    local totalDetik =
        (hari * 86400) +
        (jam * 3600) +
        (menit * 60)

    -- Minimal 1 jam
    totalDetik = math.max(3600, totalDetik)

    -- Bulatkan ke atas ke kelipatan 1 jam
    totalDetik = math.ceil(totalDetik / 3600) * 3600

    -- ❌ batas maksimal 365 hari dalam detik
    local maxDetik = 365 * 86400
    if totalDetik > maxDetik then
        gg.alert("❌ MAKSIMAL 365 HARI")
        return
    end

    int50 = {totalDetik}

    gg.toast(
        string.format(
            "BOOSTER: %d Hari %d Jam %d Menit",
            hari, jam, menit
        )
    )
end
 
