function time(option)
    LoadingAuto("Loading...", 2)
    gg.processResume()
    gg.clearResults()
    gg.setVisible(false)

if option == "lm1" or option == "lm8" or option == "Digging_X2" then

    local t = gg.prompt(
        {"Hari", "Jam", "Menit"},
        {"0", "1", "0"},
        {"number", "number", "number"}
    )

    if not t then
        gg.toast("CANCELLED")
        return
    end

    local hari  = tonumber(t[1]) or 0
    local jam   = tonumber(t[2]) or 0
    local menit = tonumber(t[3]) or 0

    if hari < 0 or hari > 365 then
        gg.alert("❌ MAKSIMAL 365 HARI")
        return
    end

    local totalDetik = (hari * 86400) + (jam * 3600) + (menit * 60)
    totalDetik = math.max(3600, totalDetik)
    totalDetik = math.ceil(totalDetik / 3600) * 3600

    if totalDetik > 365 * 86400 then
        gg.alert("❌ MAKSIMAL 365 HARI")
        return
    end

	gg.toast(
	    string.format(
	        "BOOSTER:\n%d Hari %d Jam %d Menit",
	        hari, jam, menit
	    )
	)
    add_to_7 = 0
    add_to_8 = totalDetik

    if option == "lm1" then
        add_to_6 = "0"
        add_to_5 = "1701669204"
        add_to_4 = "1718511967"
        add_to_3 = "1936029289"
        add_to_2 = "1278437475"
        add_to_1 = "1952533798"

    elseif option == "lm8" then
    add_to_6 = "0032586Ch"
    add_to_5 = "6C416472h"
    add_to_4 = "61776552h"
    add_to_3 = "79746974h"
    add_to_2 = "6E456465h"
    add_to_1 = "6D69542Ch" 

	elseif option == "Digging_X2" then
    add_to_6 = "3237230"
    add_to_5 = "1766679666"
    add_to_4 = "1635214674"
    add_to_3 = "2037672308"
    add_to_2 = "1850041445"
    add_to_1 = "1835619372" 
    end

    setdAhI()
    return
end
end


