function Time_Train()
    gg.toast("Tunggu Sebentar, saya akan kembali...")
    gg.processResume()
    gg.clearResults()
    gg.searchNumber("1600407924;51", gg.TYPE_DWORD)
    gg.refineNumber("51", gg.TYPE_DWORD)

    local r = gg.getResults(3)

    local t = {}
    for i = 1, #r do

        t[i] = {
            address = r[i].address + 0x34,
            flags = gg.TYPE_FLOAT,
            value = 3,
            freeze = false
        }
    end
    gg.setValues(t)
end

local XP_ITEM = {
    PENDANT           = {1852141582, 1953390948, 0, 0, 0, 0},
    RING              = {1852404232, 103, 0, 0, 0, 0},
    PEARL_CHOKER      = {1634037778, 1701735538, 27491, 0, 0, 0},
    EARRINGS          = {1918985488, 1735289202, 115, 0, 0, 0},
    DIADEM            = {1634296844, 7169380, 13407, 0, 0, 0},
    FEATHER_EAR_RINGS = {1634035230, 1919248500, 1920098629, 1936158313, 0, 0},
	SUGAR			  = {1735750410, 29281, 0, 0, 0, 0},
	BREAD			  = {1701995018, 25697, 0, 0, 0, 0},
}

function XP_Train(itemName)

    local item = XP_ITEM[itemName]
    if not item then
        gg.alert("Item tidak ditemukan : "..tostring(itemName))
        return
    end

    local input = gg.prompt(
        {"Masukkan jumlah "..itemName.." : (Maks 500)"},
        {"1"},
        {"number"}
    )

    if not input then return end

    local amount = tonumber(input[1])
    if amount == nil or amount < 1 or amount > 500 then
        gg.alert("Hanya bisa angka 1 sampai 500")
        return
    end

    gg.toast("Loading...")
    gg.processResume()
    gg.clearResults()

    gg.searchNumber("1600407924;51", gg.TYPE_DWORD)
    gg.refineNumber("51", gg.TYPE_DWORD)

    local result = gg.getResults(3)

    if #result == 0 then
        gg.alert("Anchor tidak ditemukan")
        return
    end

    for _, r in ipairs(result) do
        local base = r.address

        gg.setValues({
            {
                address = base + 0x34,
                flags = gg.TYPE_FLOAT,
                value = 3
            }
        })

        for g = 0,4 do

            local shift = g * 76 * 4

            local values = {
                {
                    address = base - (85 * 4) - shift,
                    flags = gg.TYPE_DWORD,
                    value = 1
                },
                {
                    address = base - (96 * 4) - shift,
                    flags = gg.TYPE_DWORD,
                    value = amount
                },
                {
                    address = base - (97 * 4) - shift,
                    flags = gg.TYPE_DWORD,
                    value = 0
                }
            }

            local offset = 103
            for _, v in ipairs(item) do
                table.insert(values,{
                    address = base - (offset * 4) - shift,
                    flags = gg.TYPE_DWORD,
                    value = v
                })
                offset = offset - 1
            end

            gg.setValues(values)
        end
    end

    gg.toast(itemName.." ACTIVATED")
end

function Items_Train()
    gg.clearResults()

    local GIFT = ""

    local function pretty(t)
        return GIFT .. "  " .. t
    end

    local menu = {
        {
            label = pretty("📿 • PENDANT | LIONTIN"),
            func = function()
                XP_Train("PENDANT")
            end
        },
        {
            label = pretty("💍 • RING | CINCIN"),
            func = function()
                XP_Train("RING")
            end
        },
        {
            label = pretty("🦪 • PEARL CHOKER | KALUNG MUTIARA"),
            func = function()
                XP_Train("PEARL_CHOKER")
            end
        },
        {
            label = pretty("✨ • EARRINGS | ANTING"),
            func = function()
                XP_Train("EARRINGS")
            end
        },
        {
            label = pretty("👑 • DIADEM | MAHKOTA"),
            func = function()
                XP_Train("DIADEM")
            end
        },
        {
            label = pretty("🪶 • FEATHER EAR RINGS | ANTING BULU"),
            func = function()
                XP_Train("FEATHER_EAR_RINGS")
            end
        },
    }

    local labels = {}
    for i, v in ipairs(menu) do
        labels[i] = v.label
    end

    local choice = gg.choice(labels, nil, "🎯CHOOSE ITEMS")

    if not choice then
        gg.toast("SELECT ITEMS")
        gg.setVisible(false)
        return
    end

    menu[choice].func()
end

function XP_Card_Train()

    local input = gg.prompt(
        {"Masukkan jumlah Mahkota (1 - 500)"},
        {"500"},
        {"number"}
    )

    if input == nil then return end

    local crown = tonumber(input[1])
    if crown == nil or crown < 1 or crown > 500 then
        gg.alert("Hanya bisa angka 1 sampai 500")
        return
    end

    gg.toast("Loading...")
    gg.processResume()
    gg.clearResults()

    gg.searchNumber("1600407924;51", gg.TYPE_DWORD)
    gg.refineNumber("51", gg.TYPE_DWORD)

    local r = gg.getResults(3)

    if not r or #r == 0 then
        gg.alert("Anchor tidak ditemukan")
        return
    end

    for i = 1, #r do

        local base = r[i].address

        gg.setValues({
            {
                address = base + 0x34,
                flags = gg.TYPE_FLOAT,
                value = 3
            }
        })

        for g = 0, 4 do

            local shift = g * 76 * 4

            gg.setValues({
                { address = base - (43 * 4) - shift, flags = gg.TYPE_DWORD, value = 896230241 },
                { address = base - (44 * 4) - shift, flags = gg.TYPE_DWORD, value = 1348420452 },
                { address = base - (45 * 4) - shift, flags = gg.TYPE_DWORD, value = 1918976790 }
            })

            gg.setValues({
                { address = base - (85 * 4) - shift, flags = gg.TYPE_DWORD, value = 1 }
            })

            gg.setValues({
                { address = base - (96 * 4) - shift, flags = gg.TYPE_DWORD, value = crown },
                { address = base - (97 * 4) - shift, flags = gg.TYPE_DWORD, value = 0 },
                { address = base - (98 * 4) - shift, flags = gg.TYPE_DWORD, value = 0 },
                { address = base - (99 * 4) - shift, flags = gg.TYPE_DWORD, value = 0 },
                { address = base - (100 * 4) - shift, flags = gg.TYPE_DWORD, value = 0 },
                { address = base - (101 * 4) - shift, flags = gg.TYPE_DWORD, value = 13407 },
                { address = base - (102 * 4) - shift, flags = gg.TYPE_DWORD, value = 7169380 },
                { address = base - (103 * 4) - shift, flags = gg.TYPE_DWORD, value = 1634296844 }
            })

        end
    end

    gg.toast("XP + CARD TRAIN ACTIVATED ")
end


function XP_Plane()

    local p = gg.prompt(
        {"Masukkan Jumlah Mahkota (1 - 500)"},
        {[1] = "500"},
        {[1] = "number"}
    )

    if p == nil then
        return
    end

    local xp = tonumber(p[1])

    if xp == nil or xp < 1 or xp > 500 then
        gg.alert("Input hanya 1 - 500")
        return
    end

    LoadingAuto("Change Value Box", 2)
    gg.processResume()
    gg.clearResults()

    gg.searchNumber("231928234002000", gg.TYPE_QWORD)

    local count = gg.getResultsCount()
    local val = gg.getResults(count)

    for i, v in ipairs(val) do
        v.address = v.address - 0x24
    end

    val = gg.getValues(val)

    for i, v in ipairs(val) do
        v.address = v.value
    end

    gg.loadResults(val)

    for i, v in ipairs(val) do
        v.address = v.address - 0x2F0
    end

    val = gg.getValues(val)

    for i, v in ipairs(val) do
        v.address = v.value
    end

    gg.loadResults(val)

    local offsets = {
        0x08,
        0x58,
        0xA8,
        0xF8,
        -0x188,
        -0x138,
        -0xE8,
        0x148
    }

    local edits = {}

    for _, off in ipairs(offsets) do

        table.insert(edits,{
            address = val[1].address + off,
            flags = gg.TYPE_DWORD,
            value = xp
        })

        table.insert(edits,{
            address = val[1].address + off + 0x08,
            flags = gg.TYPE_DWORD,
            value = 1634296844
        })

        table.insert(edits,{
            address = val[1].address + off + 0x0C,
            flags = gg.TYPE_DWORD,
            value = 7169380
        })

        table.insert(edits,{
            address = val[1].address + off + 0x10,
            flags = gg.TYPE_DWORD,
            value = 13407
        })

        table.insert(edits,{
            address = val[1].address + off + 0x14,
            flags = gg.TYPE_DWORD,
            value = 0
        })

        table.insert(edits,{
            address = val[1].address + off + 0x18,
            flags = gg.TYPE_DWORD,
            value = 0
        })

        table.insert(edits,{
            address = val[1].address + off + 0x1C,
            flags = gg.TYPE_DWORD,
            value = 0
        })

    end

    gg.setValues(edits)

hack_XP_Plane_2()

    gg.toast("CHANGE QUANTITY BOX")

end

function hack_XP_Plane_2()

    gg.processResume()
    gg.clearResults()

    LoadingAuto("Change Quantity Crown", 2)

    gg.searchNumber("231928234002000", gg.TYPE_QWORD)

    local count = gg.getResultsCount()
    local r = gg.getResults(count)

    for i, v in ipairs(r) do
        v.address = v.address - 0x24
    end

    r = gg.getValues(r)

    for i, v in ipairs(r) do
        v.address = v.value
    end

    gg.loadResults(r)

    -- OFFSET TIME VERSI BARU
    local offsets = {
        -0x318,
        0xA8,
        0x1E8,
        0x328,
        0x468,
        0x5A8,
        0x6E8,
        0x828,
        0x968
    }

    local edits = {}

    for _, off in ipairs(offsets) do

        table.insert(edits,{
            address = r[1].address + off,
            flags = gg.TYPE_DWORD,
            value = 1
        })

    end

    gg.setValues(edits)

    gg.clearResults()

    gg.toast("XP PLANE ACTIVATED")

end


