    )

    if input == nil then return end

    local amount = tonumber(input[1])

    if amount == nil or amount < 100000 or amount > 550000 then
        gg.alert("Hanya bisa angka 100000 sampai 550000")
        return
    end

    gg.clearResults()

    gg.searchNumber(
        "70786506h;6F6F5A1Ah;73657551h;65684374h;00007473h",
        gg.TYPE_DWORD
    )

    gg.refineNumber("70786506h", gg.TYPE_DWORD)

    local results = gg.getResults(8)

    if #results < 8 then
        gg.alert("Hasil kurang dari 8! Scan ulang.")
        return
    end

    local edits = {}

    for i, v in ipairs(results) do

        table.insert(edits,{
            address = v.address - 8,
            flags = gg.TYPE_DWORD,
            value = 0
        })

        table.insert(edits,{
            address = v.address - 4,
            flags = gg.TYPE_DWORD,
            value = amount
        })

    end

    gg.setValues(edits)
    gg.alert("Zoo order successfully edited")

end

