function Duplicate_Buildings(name, kodeGrup1, kodeGrup2, nilaiRefine2)
    gg.clearResults()
    gg.setRanges(gg.REGION_C_ALLOC)

    -- Step 1: freeze offsets -44 and -40
    gg.searchNumber(kodeGrup1, gg.TYPE_DWORD)
    gg.refineNumber("77", gg.TYPE_DWORD)

    local count = gg.getResultCount()
    if count == 0 then
        gg.alert("🔙 Value 77 for " .. name .. " not found")
        return
    end

    local results = gg.getResults(count)
    local lock = {}
    for i, v in ipairs(results) do
        lock[#lock + 1] = {address = v.address - 44, value = 0, flags = gg.TYPE_DWORD, freeze = true}
        lock[#lock + 1] = {address = v.address - 40, value = 0, flags = gg.TYPE_DWORD, freeze = true}
    end
    gg.addListItems(lock)
    gg.setValues(lock)
    gg.toast("✅ " .. name .. " offsets frozen")

    -- Step 2: set amount
    gg.clearResults()
    gg.searchNumber(kodeGrup2, gg.TYPE_DWORD)
    gg.refineNumber(tostring(nilaiRefine2), gg.TYPE_DWORD)

    local count2 = gg.getResultCount()
    if count2 == 0 then
        gg.alert("🔙 Value " .. nilaiRefine2 .. " for " .. name .. " not found")
        return
    end

    local p = gg.prompt({"How many " .. name .. " do you want?"}, {1}, {"number"})
    if not p then return end

    local results2 = gg.getResults(count2)
    for i, v in ipairs(results2) do
        results2[i].value = p[1]
        results2[i].freeze = true
    end
    gg.addListItems(results2)
    gg.setValues(results2)
    gg.toast("✅ " .. name .. " amount set to: " .. p[1])
end
