function Unlock_Animal()
gg.alert([[
🐾 TIPS UNLOCK ANIMALS (KHUSUS AKUN YANG MEMPUNYAI ZOO)
📋Masuk Ke Zoo ➞ Tunggu Loading ➞ Semua Hewan Siap Dimasukkan Ke Kandang ]])
    gg.clearResults()

    gg.setRanges(
        gg.REGION_C_ALLOC |
        gg.REGION_ANONYMOUS |
        gg.REGION_OTHER
    )

	LoadingAuto("🔎 SEARCHING ANIMAL DATA 🐘", 2)

    gg.searchNumber(
        "6D65660Ch;6C616D08h",
        gg.TYPE_DWORD
    )

    local count = gg.getResultCount()

    if count == 0 then
        gg.searchNumber(
            "1835361804;1814154504",
            gg.TYPE_DWORD
        )
        count = gg.getResultCount()
    end

    if count == 0 then
        gg.alert(
            "🔙 DATA NOT FOUND!\n\n" ..
            "PLEASE ENTER THE ZOO FIRST."
        )
        return
    end

    local results = gg.getResults(count)
    local edits = {}

    gg.toast("⚡ PROCESSING ANIMAL DATA...")

    for i, v in ipairs(results) do

        local value
        local pos = ((i - 1) % 4) + 1

        if pos == 1 then
            value = 30
        elseif pos == 2 then
            value = 30
        elseif pos == 3 then
            value = 15
        else
            value = 10
        end

        edits[#edits + 1] = {
            address = v.address + (6 * 4),
            flags = gg.TYPE_DWORD,
            value = value
        }

    end

    gg.setValues(edits)
	gg.clearResults()
    gg.toast("✅ SUCCESS!")

    gg.alert(
        "✅ PROCESS COMPLETE\n\n" ..
        "ALL ANIMALS HAVE BEEN OPENED"
    )
end


