function Mine_Depth()

    gg.setVisible(false)
    gg.clearResults()
    gg.setRanges(gg.REGION_C_ALLOC)

    gg.toast("⛏️ Searching Mine Depth...")
	LoadingAuto("Calculating Depth", 5)
    -- SEARCH
    gg.searchNumber(
        "1734960142;1735289191;10;1734960148;1735289191",
        gg.TYPE_DWORD
    )

    -- REFINE KE 10
    gg.refineNumber("10", gg.TYPE_DWORD)

    local r = gg.getResults(100)

    if #r == 0 then
        gg.alert("❌ Target Not Found")
        return
    end

    -- =================================
    -- PINDAH 1 BARIS DI ATAS ANCHOR
    -- DWORD = 4 BYTE
    -- jadi offset -0x4
    -- =================================

    local edit = {}

    for i,v in ipairs(r) do
        edit[i] = {
            address = v.address - 0x4,
            flags = gg.TYPE_DWORD
        }
    end

    edit = gg.getValues(edit)

    -- INPUT VALUE
    local input = gg.prompt(
        {"⛏️ Enter Mine Depth:"},
        {100},
        {"number"}
    )

    if not input then
        return
    end

    local value = tonumber(input[1])

    if not value then
        gg.alert("❌ Invalid Number")
        return
    end

    -- EDIT VALUE
    for i,v in ipairs(edit) do
        v.value = value
    end

    gg.setValues(edit)

    gg.alert(
        "✅ MINE DEPTH MODIFIED\n\n" ..
        "⛏️ DEPTH: "..value
    )

    gg.clearResults()
end

