-- Modified REGATTA function to accept league value
function REGATTA(leagueValue)
    gg.clearResults()
    gg.searchNumber("65540;1;" .. leagueValue .. "::493", gg.TYPE_DWORD, false, gg.SIGN_EQUAL, 0, -1)
    gg.refineNumber("65540", gg.TYPE_DWORD, false, gg.SIGN_EQUAL, 0, -1, 0)

    local cnt = gg.getResultCount()
    if cnt == 0 then
        gg.toast("No results found 😔")
        gg.clearResults()
        return
    end
    local valueRes = gg.getResults(cnt)

    local ptrCandidates = {}
    for _, v in ipairs(valueRes) do
        local base = v.address
        local checks = {
            {address = base + 0x1E8, flags = gg.TYPE_DWORD},
            {address = base + 0x1EC, flags = gg.TYPE_DWORD},
            {address = base + 0x1F0, flags = gg.TYPE_DWORD},
            {address = base + 0x208, flags = gg.TYPE_QWORD},
        }
        local vals = gg.getValues(checks)

        local ok = (vals[1].value == 1)
               and (vals[2].value == leagueValue)
               and (vals[3].value == 1)

        if ok then
            local ptr = vals[4].value
            if ptr ~= nil and ptr ~= 0 and ptr > 0x10000 then
                table.insert(ptrCandidates, {address = ptr, flags = gg.TYPE_QWORD})
            end
        end
    end

    if #ptrCandidates == 0 then
        gg.toast("No valid pointers found 😞")
        gg.clearResults()
        return
    end

    local choices = {"150", "200", "300"}
    local menu = gg.choice(choices, nil, "REGATTA POINTS! 🎯")
    if menu == nil then
        gg.toast("Point selection cancelled ❌")
        gg.clearResults()
        return
    end
    local selectedValue = tonumber(choices[menu])

    local ptrList = gg.getValues(ptrCandidates)
    local writes = {}
    for _, it in ipairs(ptrList) do
        table.insert(writes, {address = it.address,       flags = gg.TYPE_DWORD, value = 0})
        table.insert(writes, {address = it.address + 0x4, flags = gg.TYPE_DWORD, value = selectedValue})
    end
    if #writes > 0 then 
        gg.setValues(writes) 
        gg.toast("🎉 Hacked REGATTA POINT successfully! 🚀")
    else
        gg.toast("Failed to set points 😢")
    end

    gg.removeResults(valueRes)
    gg.clearResults()
    gg.setVisible(false)
    while not gg.isVisible() do
        gg.sleep(100)  -- Rest 0.1 second per check
    end
    gg.setVisible(false)
    REGATTA_MENU()
end

function AUTO(leagueValue)
    gg.clearResults()
    gg.searchNumber("65540;1;" .. leagueValue .. "::493", gg.TYPE_DWORD, false, gg.SIGN_EQUAL, 0, -1)
    gg.refineNumber("65540", gg.TYPE_DWORD, false, gg.SIGN_EQUAL, 0, -1, 0)
    local cnt = gg.getResultCount()
    if cnt == 0 then
        gg.clearResults()
        gg.toast("❌ No results found")
        REGATTA_MENU()  -- Back to main menu
        return
    end

    local valueRes = gg.getResults(cnt)
    local patched = 0

    for _, v in ipairs(valueRes) do
        local base = v.address
        local checks = {
            {address = base + 0x1E8, flags = gg.TYPE_DWORD},
            {address = base + 0x1EC, flags = gg.TYPE_DWORD},
            {address = base + 0x1F0, flags = gg.TYPE_DWORD},
        }
        local vals = gg.getValues(checks)

        local ok = (vals[1].value == 1)
                and (vals[2].value == leagueValue)
                and (vals[3].value == 1)

        if ok then
            local aVal = gg.getValues({{address = base + 0x00C8, flags = gg.TYPE_DWORD}})[1].value
            local bVal = bit32.bxor(aVal, 5000)
            gg.setValues({
                {address = base + 0x00CC, flags = gg.TYPE_DWORD, value = bVal}
            })

            patched = patched + 1
        end
    end

    if patched > 0 then
        gg.toast("🎉 Hacked AUTOMATIC successfully! 🚀")
    else
        gg.toast("ℹ️ No matching blocks passed checks")
    end

    gg.clearResults()
    gg.setVisible(false)
    while not gg.isVisible() do
        gg.sleep(100)  -- Rest 0.1 second per check
    end
    gg.setVisible(false)
    REGATTA_MENU()  -- Return to main menu
end

function REGATTA_AUTO(leagueValue)
    gg.clearResults()
    gg.searchNumber("65540;1;" .. leagueValue .. "::493", gg.TYPE_DWORD, false, gg.SIGN_EQUAL, 0, -1)
    gg.refineNumber("65540", gg.TYPE_DWORD, false, gg.SIGN_EQUAL, 0, -1, 0)

    local cnt = gg.getResultCount()
    if cnt == 0 then
        gg.clearResults()
        gg.toast("❌ No results found")
        REGATTA_MENU()  -- Back to main menu
        return
    end
    local valueRes = gg.getResults(cnt)

    local ptrCandidates = {}
    local autoBases = {}

    -- Scan and collect pointers for REGATTA + store bases for AUTO
    for _, v in ipairs(valueRes) do
        local base = v.address
        local checks = {
            {address = base + 0x1E8, flags = gg.TYPE_DWORD},
            {address = base + 0x1EC, flags = gg.TYPE_DWORD},
            {address = base + 0x1F0, flags = gg.TYPE_DWORD},
            {address = base + 0x208, flags = gg.TYPE_QWORD},
        }
        local vals = gg.getValues(checks)

        local ok = (vals[1].value == 1)
               and (vals[2].value == leagueValue)
               and (vals[3].value == 1)

        if ok then
            local ptr = vals[4].value
            if ptr ~= nil and ptr ~= 0 and ptr > 0x10000 then
                table.insert(ptrCandidates, {address = ptr, flags = gg.TYPE_QWORD})
            end
            table.insert(autoBases, base)
        end
    end

    -- Step 1: Hack REGATTA POINTS
    local pointsPatched = 0
    local proceedAuto = false
    if #ptrCandidates == 0 then
        gg.toast("ℹ️ No valid pointers found")
    else
        local choices = {"150", "200", "300"}
        local menu = gg.choice(choices, nil, "REGATTA POINTS! 🎯")
        if menu == nil then
            gg.clearResults()
            gg.toast("ℹ️ REGATTA cancelled")
            REGATTA_MENU()  -- Back to main menu
            return
        end
        local selectedValue = tonumber(choices[menu])

        local ptrList = gg.getValues(ptrCandidates)
        local writes = {}
        for _, it in ipairs(ptrList) do
            table.insert(writes, {address = it.address,       flags = gg.TYPE_DWORD, value = 0})
            table.insert(writes, {address = it.address + 0x4, flags = gg.TYPE_DWORD, value = selectedValue})
        end
        if #writes > 0 then
            gg.setValues(writes)
            pointsPatched = #ptrList
            proceedAuto = true
            gg.toast("🎉 Hacked REGATTA POINT successfully! 🚀")
        end
    end

    -- Step 2: Only process AUTO if REGATTA was successful
    if proceedAuto and pointsPatched > 0 then
        local patched = 0
        for _, base in ipairs(autoBases) do
            local aVal = gg.getValues({{address = base + 0x00C8, flags = gg.TYPE_DWORD}})[1].value
            local bVal = bit32.bxor(aVal, 5000)
            gg.setValues({
                {address = base + 0x00CC, flags = gg.TYPE_DWORD, value = bVal}
            })
            patched = patched + 1
        end

        if patched > 0 then
            gg.toast("🎉 Hacked AUTOMATIC successfully! 🚀")
        else
            gg.toast("ℹ️ No matching blocks passed checks for AUTO")
        end
    else
        gg.toast("ℹ️ Skipped AUTO (REGATTA not applied)")
    end

    gg.removeResults(valueRes)
    gg.clearResults()
    gg.setVisible(false)
    while not gg.isVisible() do
        gg.sleep(100)  -- Rest 0.1 second per check
    end
    gg.setVisible(false)
    REGATTA_MENU()  -- Return to main menu
end

