function Unlock_Artifact()
    gg.alert([[
💡 TIPS UNLOCK artefak
📝Tunggu Loading ➞ Semua Artefak Terbuka
]])

    gg.clearResults()

    local GEM = "💾"

    local function pretty(t)
        return GEM .. "  " .. t
    end

    local labels = {
        pretty("Ca + A + O"),
    }

    local ranges = {
        gg.REGION_C_ALLOC | gg.REGION_ANONYMOUS | gg.REGION_OTHER
    }

    local choice = gg.choice(labels, nil, " ✅ Select Memory Range")

    if not choice then
        gg.toast("💾 PILIH RENTANG MEMORI")
        return
    end

    gg.setRanges(ranges[choice])

    local t = {}

    local function addSafeResults(results, offset)
        local check = {}

        for _, v in ipairs(results) do
            table.insert(check,{
                address = v.address - offset,
                flags = gg.TYPE_DWORD
            })
        end

        check = gg.getValues(check)

        for _, v in ipairs(check) do
            if v.value == 0 or v.value == 1 or v.value == 2 or v.value == 3 then
                table.insert(t,{
                    address = v.address,
                    flags = gg.TYPE_DWORD,
                    value = 3
                })
            end
		gg.clearResults()
        end
    end

    -- Search 1
    gg.clearResults()
    LoadingAuto("Unlock Artifact Section 1", 2)
    gg.searchNumber("74726118h;74706D65h;00000079h;74726116h;64616873h", gg.TYPE_DWORD)
    gg.refineNumber("74706D65h", gg.TYPE_DWORD)
    local r = gg.getResults(2000)
    addSafeResults(r, (16 * 4))

    -- Search 2
    gg.clearResults()
    LoadingAuto("Unlock Artifact Section 2", 2)
    gg.searchNumber("74726116h;64656B63h;74726114h;00797470h;74726112h;00006461h", gg.TYPE_DWORD)
    gg.refineNumber("64656B63h", gg.TYPE_DWORD)
    r = gg.getResults(2000)
    addSafeResults(r, (10 * 4))

    -- Search 3
    gg.clearResults()
    LoadingAuto("Unlock Artifact Section 3", 2)
    gg.searchNumber("7472610Ah;74726118h;656B636Fh;00000064h;74726116h;7974706Dh;74726116h", gg.TYPE_DWORD)
    gg.refineNumber("656B636Fh", gg.TYPE_DWORD)
    r = gg.getResults(2000)
    addSafeResults(r, (10 * 4))

    -- Search 4
    gg.clearResults()
    LoadingAuto("Unlock Artifact Section 4", 2)
    gg.searchNumber("7472610Ch;7472611Ah;6B636F6Ch;00006465h;74726118h;74706D65h;00000079h;74726116h;64616873h", gg.TYPE_DWORD)
    gg.refineNumber("6B636F6Ch", gg.TYPE_DWORD)
    r = gg.getResults(2000)
    addSafeResults(r, (10 * 4))

    -- Search 5
    gg.clearResults()
    LoadingAuto("Unlock Artifact Section 5", 2)
    gg.searchNumber("7472611Ah;6B636F6Ch;00006465h;74726118h;74706D65h;00000079h", gg.TYPE_DWORD)
    gg.refineNumber("6B636F6Ch", gg.TYPE_DWORD)
    r = gg.getResults(2000)
    addSafeResults(r, (10 * 4))

    gg.clearResults()

    if #t > 0 then
        gg.setValues(t)
        gg.alert(
			"🏆 UNLOCK ARTIFACT SUCCESS 🏆\nEdited: "..#t.."\n" ..
			"Created by RDHT RMDN")
    else
        gg.alert("❌ DATA NOT FOUND")
    end
end

