function LoadingAuto(text, speed)
    for i = 0, 100 do
        local barCount = math.floor(i / 10)
        local bar = string.rep("■", barCount) ..
                    string.rep("□", 10 - barCount)

        gg.toast(string.format("%s\n[%s] %d%%", text, bar, i))
        gg.sleep(speed or 3)
    end
end
