local URLS = {
    Achievement      =  "https://raw.githubusercontent.com/RDHT1010/RDHT_DATABASE/refs/heads/main/ACHIEVEMENT",
    ["Unlock Animal"] = "https://raw.githubusercontent.com/RDHT1010/RDHT_DATABASE/refs/heads/main/ANIMAL",
    ["Unlock Artifact"] = "https://raw.githubusercontent.com/RDHT1010/RDHT_DATABASE/refs/heads/main/ARTIFACT",
    Card             = "https://raw.githubusercontent.com/RDHT1010/RDHT_DATABASE/refs/heads/main/CARD",
    Regatta          = "https://raw.githubusercontent.com/RDHT1010/RDHT_DATABASE/refs/heads/main/REGATA",
}

local function checkNameInFile(device, url)
    local res = gg.makeRequest(url)

    if not res or not res.content then
        return false
    end

    for line in res.content:gmatch("[^\r\n]+") do
        local name, user, deviceID, status =
            line:match("([^|]+)|([^|]+)|([^|]+)|(.+)")

        if deviceID == device then
            return true
        end
    end

    return false
end

local function getAccessInfo(device)
    local result = {}

    local features = {
        {"Achievement", "🏆"},
        {"Unlock Animal", "🐾"},
        {"Unlock Artifact", "🏺"},
        {"Card", "🃏"},
        {"Regatta", "⛵"}
    }

    local unlocked = 0
    local total = #features

    for _, item in ipairs(features) do
        local feature = item[1]
        local icon = item[2]
        -- Cek apakah feature aktif untuk device
        local active = checkNameInFile(device, URLS[feature])
        if active then
            unlocked = unlocked + 1
        end
        -- Tambahkan info feature
        table.insert(
            result,
            string.format(
                "%s %-16s ➜ %s",
                icon,
                feature,
                active and "Active" or "Inactive"
            )
        )
    end

    -- ===== Progress Bar Aman =====
    -- ===== Progress Bar =====
	unlocked = tonumber(unlocked) or 0
	total = tonumber(total) or 1
	
	local barLength = 6
	
	local percent = math.floor((unlocked / total) * 100)
	
	local filled = math.floor((unlocked * barLength) / total + 0.5)
	
	if unlocked > 0 and filled < 1 then
	    filled = 1
	end
	
	if filled > barLength then
	    filled = barLength
	end
	
	local bar = string.rep("■", filled) ..
	            string.rep("□", barLength - filled)
	
	table.insert(result, "")
	table.insert(
	    result,
	    string.format(
	        "📊 Feature : [%s] %d/%d (%d%%)",
	        bar,
	        unlocked,
	        total,
	        percent
	    )
	)
	    table.insert(result, "━━━━━━━━━━━━━━━━━━━━")
	
	    return table.concat(result, "\n")
end

local url = "https://raw.githubusercontent.com/RDHT1010/RDHT_DATABASE/refs/heads/main/LICENSE_KEYS_USERS"

local function getData()
    local res = gg.makeRequest(url)

    if not res or not res.content then
        gg.alert("❌ Failed to fetch data!")
        return nil
    end

    return res.content
end

local function Info_Account()
    LoadingAuto("Get Data Info", 5)

    local data = getData()
    if not data then return end

    local myID = getDeviceID()
    local result = ""

    for line in data:gmatch("[^\r\n]+") do
        local name, user, device, status =
            line:match("([^|]+)|([^|]+)|([^|]+)|(.+)")

        if device == myID then
            result =
				"🔑 USER INFORMATION".. "\n" ..
				"═════════════════════════\n" ..
                "👤 Name     : " .. name .. "\n" ..
                "📱 UserId   : " .. device .. "\n" ..
                "⏳ Expired  : " .. status.."\n"..
				"═════════════════════════"

            break
        end
    end

    if result == "" then
        result = "❌ Device tidak terdaftar"
    end

    gg.alert(result)
end


function Premium_Access()
    LoadingAuto("Get Data Info", 5)

    local data = getData()
    if not data then return end

    local myID = getDeviceID()
    local result = ""

    for line in data:gmatch("[^\r\n]+") do
        local name, user, device, status =
            line:match("([^|]+)|([^|]+)|([^|]+)|(.+)")

        if device == myID then
            result =
                "⭐ PREMIUM FEATURES ⭐\n\n" ..
                getAccessInfo(myID)

            break
        end
    end

    if result == "" then
        result = "❌ Device tidak terdaftar"
    end

    gg.alert(result)
end

function CheckAccess(url, callback)
local req = gg.makeRequest(url)

if not req or not req.content then
    gg.alert("❌ Failed to connect server")
    return
end

local myID = getDeviceID()

for line in req.content:gmatch("[^\r\n]+") do
    local nama, kode, deviceID, expired =
        line:match("([^|]+)|([^|]+)|([^|]+)|(.+)")

    if deviceID == myID then
        gg.toast("⭐ ACCESS FOR : " .. nama)

        if callback then
            callback()
        end
        return
    end
end

